import{_ as e,c as o,o as c,a4 as t}from"./chunks/framework.BmdFiWrL.js";const m=JSON.parse('{"title":"配置 OIDC 认证","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"guide/q10.md","filePath":"guide/q10.md","lastUpdated":1780369673000}'),d={name:"guide/q10.md"},i=t('<h1 id="配置-oidc-认证" tabindex="-1">配置 OIDC 认证 <a class="header-anchor" href="#配置-oidc-认证" aria-label="Permalink to &quot;配置 OIDC 认证&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>本文原内容适用于 v0 版本的 OIDC 配置格式，不适用于 v1 及之后版本。本页仅为保留旧链接而存在，请不要按旧字段部署新的第三方登录。</p></div><p>v1 之后 Dashboard 不再使用旧的 <code>type: oidc</code>、<code>oidcIssuer</code>、<code>oidcScopes</code> 等配置字段。当前版本的第三方登录统一使用 OAuth2 绑定配置。</p><p>如果你的 OIDC 提供方支持标准 OAuth2/OIDC 端点，请按 <a href="/guide/q14.html">设置 OAuth 2.0 绑定</a> 中的新版结构填写：</p><ul><li><code>client_id</code></li><li><code>client_secret</code></li><li><code>endpoint.auth_url</code></li><li><code>endpoint.token_url</code></li><li><code>scopes</code></li><li><code>user_info_url</code></li><li><code>user_id_path</code></li></ul><p>配置完成并重启 Dashboard 后，先登录本地账户，在个人信息页绑定第三方账户，再使用登录页的 OAuth2 按钮登录。</p>',6),a=[i];function l(s,r,_,n,p,u){return c(),o("div",null,a)}const f=e(d,[["render",l]]);export{m as __pageData,f as default};
